import{_ as i,o as s,c as a,ag as t}from"./chunks/framework.Lq6hU67C.js";const u=JSON.parse('{"title":"ILPP diagnostics","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/ilpp-diagnostics.md","filePath":"how-to/ilpp-diagnostics.md"}'),o={name:"how-to/ilpp-diagnostics.md"};function l(n,e,r,d,c,p){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="ilpp-diagnostics" tabindex="-1">ILPP diagnostics <a class="header-anchor" href="#ilpp-diagnostics" aria-label="Permalink to &quot;ILPP diagnostics&quot;">​</a></h1><p>Enable ILPP diagnostics to see injection statistics in the Unity Console after script recompilation.</p><h2 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h2><ol><li>Open <strong>Window → Addressables Leak Detector</strong></li><li>Settings menu (⋮) → <strong>ILPP diagnostics</strong></li><li>Wait for script recompile</li></ol><p>Diagnostics write to <code>Library/AddressablesLeakDetector/ilpp_settings.json</code> (<code>ilppDiagnosticsEnabled: true</code>).</p><h2 id="what-you-see" tabindex="-1">What you see <a class="header-anchor" href="#what-you-see" aria-label="Permalink to &quot;What you see&quot;">​</a></h2><p>After recompile, the Console may report per-assembly injection counts, for example:</p><ul><li>Assemblies processed</li><li>Load call sites injected</li><li>Release call sites injected</li><li>Skipped assemblies (exclude list or gate disabled)</li></ul><p>Use this to confirm your gameplay assemblies are instrumented.</p><h2 id="when-to-use" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to use&quot;">​</a></h2><ul><li>First import — verify ILPP runs on your scripts.</li><li>No Live Leaks entries — confirm loads happen in non-excluded assemblies.</li><li>After changing assembly exclude list — confirm expected assemblies skipped.</li></ul><h2 id="related-settings" tabindex="-1">Related settings <a class="header-anchor" href="#related-settings" aria-label="Permalink to &quot;Related settings&quot;">​</a></h2><p>All ILPP-facing toggles live in the same JSON file. See <a href="./../reference/ilpp-settings.html">ILPP settings (JSON)</a>.</p><h2 id="disable-for-daily-work" tabindex="-1">Disable for daily work <a class="header-anchor" href="#disable-for-daily-work" aria-label="Permalink to &quot;Disable for daily work&quot;">​</a></h2><p>Turn diagnostics off to reduce Console noise. Injection still runs according to <strong>Recording</strong> and exclude list settings.</p>',15)])])}const g=i(o,[["render",l]]);export{u as __pageData,g as default};
